 1→/**
 2→ * CLI DPoP — thin wrapper around shared DPoP primitives.
 3→ *
 4→ * Re-exports generateKeyPair and createDPoPProof from app/shared/dpop.
 5→ * Adds generateDPoPKeyMaterial() convenience for CLI config storage
 6→ * (returns only JWK + thumbprint, no CryptoKey handles).
 7→ */
 8→import {
 9→  generateKeyPair,
10→  createDPoPProof as sharedCreateDPoPProof,
11→  type DPoPKeyPair,
12→} from "../app/shared/dpop";
13→
14→export type { DPoPKeyPair } from "../app/shared/dpop";
15→
16→export type DPoPKeyMaterial = {
17→  privateJwk: JsonWebKey;
18→  publicJwk: JsonWebKey;
19→  thumbprint: string;
20→};
21→
22→/**
23→ * Generate DPoP key material suitable for CLI config persistence.
24→ * Returns only serializable JWKs (no CryptoKey handles).
25→ */
26→export async function generateDPoPKeyMaterial(): Promise<DPoPKeyMaterial> {
27→  const kp = await generateKeyPair();
28→  return {
29→    privateJwk: kp.privateJwk,
30→    publicJwk: kp.publicJwk,
31→    thumbprint: kp.thumbprint,
32→  };
33→}
34→
35→/**
36→ * Create a fresh DPoP proof JWT for a single HTTP request.
37→ * Delegates to the shared implementation, accepting JWK private key.
38→ */
39→export async function createDPoPProof(
40→  privateJwk: JsonWebKey,
41→  publicJwk: JsonWebKey,
42→  method: string,
43→  url: string,
44→): Promise<string> {
45→  return sharedCreateDPoPProof(privateJwk, publicJwk, method, url);
46→}
