 36→export class BrainHttpClient {
 37→  private baseUrl: string;
 38→  private workspaceId: string;
 39→  private accessToken: string;
 40→  private refreshToken: string;
 41→  private tokenExpiresAt: number;
 42→  private clientId: string;
 43→  // DPoP fields
 44→  private dpopPrivateJwk?: JsonWebKey;
 45→  private dpopPublicJwk?: JsonWebKey;
 46→  private dpopThumbprint?: string;
 47→  private dpopAccessToken?: string;
 48→  private dpopTokenExpiresAt?: number;
 49→  private identityId?: string;
 50→
 51→  constructor(config: BrainConfig) {
 52→    this.baseUrl = config.server_url.replace(/\/$/, "");
 53→    this.workspaceId = config.workspace;
 54→    this.accessToken = config.access_token;
 55→    this.refreshToken = config.refresh_token;
 56→    this.tokenExpiresAt = config.token_expires_at;
 57→    this.clientId = config.client_id;
 58→    this.dpopPrivateJwk = config.dpop_private_jwk;
 59→    this.dpopPublicJwk = config.dpop_public_jwk;
 60→    this.dpopThumbprint = config.dpop_thumbprint;
 61→    this.dpopAccessToken = config.dpop_access_token;
 62→    this.dpopTokenExpiresAt = config.dpop_token_expires_at;
 63→    this.identityId = config.identity_id;
 64→  }
 65→
 66→  // ---------------------------------------------------------------------------
 67→  // DPoP key material bootstrap
 68→  // ---------------------------------------------------------------------------
 69→
 70→  private async ensureDPoPKeyMaterial(): Promise<void> {
 71→    if (this.dpopPrivateJwk && this.dpopPublicJwk && this.dpopThumbprint) return;
 72→
 73→    const material = await generateDPoPKeyMaterial();
 74→    this.dpopPrivateJwk = material.privateJwk;
 75→    this.dpopPublicJwk = material.publicJwk;
 76→    this.dpopThumbprint = material.thumbprint;
 77→    await this.persistDPoPState();
 78→  }
 79→
 80→  // ---------------------------------------------------------------------------
 81→  // Identity discovery
 82→  // ---------------------------------------------------------------------------
 83→
 84→  private async ensureIdentity(): Promise<void> {
 85→    if (this.identityId) return;
 86→
 87→    const res = await fetch(`${this.baseUrl}/api/auth/identity/${this.workspaceId}`);
 88→    if (!res.ok) {
 89→      throw new Error(`Identity discovery failed: ${res.status}. Run 'brain init' to re-authenticate.`);
 90→    }
 91→    const data = await res.json() as { identity_id: string };
 92→    this.identityId = data.identity_id;
 93→    await this.persistDPoPState();
 94→  }
 95→
 96→  // ---------------------------------------------------------------------------
 97→  // DPoP token acquisition via intent submission + token endpoint
 98→  // ---------------------------------------------------------------------------
 99→
100→  private async ensureDPoPToken(): Promise<void> {
101→    // Refresh 30 seconds before expiry
102→    if (
103→      this.dpopAccessToken &&
104→      this.dpopTokenExpiresAt &&
105→      Date.now() < (this.dpopTokenExpiresAt - 30) * 1000
106→    ) {
107→      return;
108→    }
109→
110→    await this.ensureDPoPKeyMaterial();
111→    await this.ensureIdentity();
112→
113→    // Step 1: Submit intent with broad authorization_details
114→    const intentRes = await fetch(`${this.baseUrl}/api/auth/intents`, {
115→      method: "POST",
116→      headers: { "Content-Type": "application/json" },
117→      body: JSON.stringify({
118→        workspace_id: this.workspaceId,
119→        identity_id: this.identityId,
