  1→/**
  2→ * DPoP Verification Middleware
  3→ *
  4→ * Brain resource server pipeline replacing authenticateMcpRequest.
  5→ * Extracts Authorization: DPoP + DPoP headers. Rejects Bearer tokens,
  6→ * session cookies, missing auth with 401 dpop_required.
  7→ * Validates token signature via AS JWKS, validates proof,
  8→ * verifies sender binding (cnf.jkt match).
  9→ *
 10→ * Pure pipeline -- domain logic has no IO imports beyond jose for JWT.
 11→ *
 12→ * Step: 03-01
 13→ */
 14→import * as jose from "jose";
 15→import { RecordId } from "surrealdb";
 16→import { jsonResponse } from "../http/response";
 17→import { validateDPoPProof } from "./dpop";
 18→import type { AsSigningKey } from "./as-key-management";
 19→import type { NonceCache } from "./nonce-cache";
 20→import type { DPoPAuthResult, BrainAction, DPoPBoundTokenClaims } from "./types";
 21→import {
 22→  checkIdentityAllowed,
 23→  type LookupIdentity,
 24→  type LookupManager,
 25→} from "./identity-lifecycle";
 26→import { createAuditEvent, type AuditEvent } from "./audit";
 27→
 28→// ---------------------------------------------------------------------------
 29→// Types
 30→// ---------------------------------------------------------------------------
 31→
 32→/** Workspace lookup port -- pure function signature (no Surreal import in domain). */
 33→export type LookupWorkspace = (
 34→  workspaceId: string,
 35→) => Promise<{ name: string; identityId: string } | undefined>;
 36→
 37→/** Port for fire-and-forget audit event logging. */
 38→export type LogAudit = (event: AuditEvent) => void;
 39→
 40→export type DPoPVerificationDeps = {
 41→  asSigningKey: AsSigningKey;
 42→  nonceCache: NonceCache;
 43→  lookupWorkspace: LookupWorkspace;
 44→  lookupIdentity?: LookupIdentity;
 45→  lookupManager?: LookupManager;
 46→  logAudit?: LogAudit;
 47→};
 48→
 49→// ---------------------------------------------------------------------------
 50→// Error response builders
 51→// ---------------------------------------------------------------------------
 52→
 53→function dpopError(
 54→  error: string,
 55→  status: number,
 56→  errorDescription?: string,
 57→): Response {
 58→  const body: Record<string, string> = { error };
 59→  if (errorDescription) {
 60→    body.error_description = errorDescription;
 61→  }
 62→  return jsonResponse(body, status);
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Pipeline steps
 67→// ---------------------------------------------------------------------------
 68→
 69→type ExtractedAuth =
 70→  | { type: "dpop"; token: string }
 71→  | { type: "error"; response: Response };
 72→
 73→/** Step 1: Extract and classify the Authorization header. */
 74→function extractAuthorization(request: Request): ExtractedAuth {
 75→  const authHeader = request.headers.get("authorization");
 76→
 77→  // Check for session cookies without DPoP auth
 78→  if (!authHeader) {
 79→    const cookie = request.headers.get("cookie");
 80→    if (cookie && isSessionCookie(cookie)) {
 81→      return {
 82→        type: "error",
 83→        response: dpopError("dpop_required", 401, "Session cookies not accepted. Use DPoP."),
 84→      };
 85→    }
 86→    return {
 87→      type: "error",
 88→      response: dpopError("dpop_required", 401),
 89→    };
 90→  }
 91→
 92→  // Reject Bearer tokens
 93→  if (authHeader.startsWith("Bearer ")) {
 94→    return {
 95→      type: "error",
 96→      response: dpopError(
 97→        "dpop_required",
 98→        401,
 99→        "Bearer tokens not accepted. Use DPoP.",
100→      ),
101→    };
102→  }
103→
104→  // Must be DPoP scheme
105→  if (!authHeader.startsWith("DPoP ")) {
106→    return {
107→      type: "error",
108→      response: dpopError("dpop_required", 401),
109→    };
110→  }
111→
112→  const token = authHeader.slice(5);
113→  if (!token) {
114→    return {
115→      type: "error",
116→      response: dpopError("dpop_required", 401),
117→    };
118→  }
119→
120→  return { type: "dpop", token };
121→}
122→
123→/** Step 2: Extract DPoP proof from request header. */
124→function extractDPoPProof(request: Request): string | Response {
125→  const proof = request.headers.get("dpop");
126→  if (!proof) {
127→    return dpopError(
128→      "invalid_request",
129→      401,
130→      "DPoP proof header required",
131→    );
132→  }
133→  return proof;
134→}
135→
136→/** Step 3: Verify access token JWT signature against AS public key. */
137→async function verifyAccessToken(
138→  token: string,
139→  asSigningKey: AsSigningKey,
140→): Promise<DPoPBoundTokenClaims | Response> {
141→  try {
142→    const publicKey = await jose.importJWK(
143→      asSigningKey.publicJwk as jose.JWK,
144→      "ES256",
145→    );
146→    const { payload } = await jose.jwtVerify(token, publicKey);
147→
148→    // Extract required claims
149→    const sub = payload.sub;
150→    if (!sub) {

  1→/**
  2→ * MCP DPoP + RAR Authentication & Authorization
  3→ *
  4→ * Replaces the legacy authenticateMcpRequest + requireScope pattern.
  5→ * Uniform pipeline for all actor types (human and agent):
  6→ *   1. authenticateDPoPRequest -- verify DPoP token + proof
  7→ *   2. deriveRequestedAction  -- map HTTP method + path to BrainAction
  8→ *   3. verifyOperationScope   -- check token's authorization_details
  9→ *
 10→ * Pure function module -- no IO imports beyond downstream ports.
 11→ *
 12→ * Step-ID: 03-04
 13→ */
 14→import { jsonResponse } from "../http/response";
 15→import { authenticateDPoPRequest, type DPoPVerificationDeps } from "../oauth/dpop-middleware";
 16→import { deriveRequestedAction } from "../oauth/route-action-map";
 17→import { verifyOperationScope } from "../oauth/rar-verifier";
 18→import type { BrainAction, DPoPAuthResult } from "../oauth/types";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Types
 22→// ---------------------------------------------------------------------------
 23→
 24→/** DPoP authenticator port -- injectable for testing. */
 25→export type DPoPAuthenticator = (
 26→  request: Request,
 27→  deps: DPoPVerificationDeps,
 28→) => Promise<DPoPAuthResult | Response>;
 29→
 30→// ---------------------------------------------------------------------------
 31→// Constraint extraction
 32→// ---------------------------------------------------------------------------
 33→
 34→/**
 35→ * Extract constraint-relevant fields from the request body.
 36→ *
 37→ * Finds the matching authorized action, reads its constraint keys,
 38→ * then extracts those same keys from the request body to build
 39→ * the requested constraints for scope verification.
 40→ */
 41→async function extractRequestConstraints(
 42→  request: Request,
 43→  requestedAction: BrainAction,
 44→  authorizedActions: BrainAction[],
 45→): Promise<Record<string, unknown> | undefined> {
 46→  // Find matching authorized action with constraints
 47→  const matchingAuth = authorizedActions.find(
 48→    (auth) =>
 49→      auth.type === requestedAction.type &&
 50→      auth.action === requestedAction.action &&
 51→      auth.resource === requestedAction.resource &&
 52→      auth.constraints !== undefined,
 53→  );
 54→
 55→  if (!matchingAuth?.constraints) return undefined;
 56→
 57→  // Read the request body to extract constraint-relevant fields
 58→  const constraintKeys = Object.keys(matchingAuth.constraints);
 59→  if (constraintKeys.length === 0) return undefined;
 60→
 61→  try {
 62→    const cloned = request.clone();
 63→    const body = await cloned.json() as Record<string, unknown>;
 64→    const requestedConstraints: Record<string, unknown> = {};
 65→    let hasConstraint = false;
 66→
 67→    for (const key of constraintKeys) {
 68→      if (key in body) {
 69→        requestedConstraints[key] = body[key];
 70→        hasConstraint = true;
 71→      }
 72→    }
 73→
 74→    return hasConstraint ? requestedConstraints : undefined;
 75→  } catch {
 76→    return undefined;
 77→  }
 78→}
 79→
 80→// ---------------------------------------------------------------------------
 81→// Pipeline
 82→// ---------------------------------------------------------------------------
 83→
 84→/**
 85→ * Authenticate and authorize an MCP request via DPoP + RAR.
 86→ *
 87→ * Returns DPoPAuthResult on success, or an error Response.
 88→ * Accepts an optional authenticator parameter for test injection.
 89→ */
 90→export async function authenticateAndAuthorize(
 91→  request: Request,
 92→  dpopDeps: DPoPVerificationDeps,
 93→  authenticator: DPoPAuthenticator = authenticateDPoPRequest,
 94→): Promise<DPoPAuthResult | Response> {
 95→  // Step 1: DPoP token + proof verification
 96→  const authResult = await authenticator(request, dpopDeps);
 97→  if (authResult instanceof Response) {
 98→    return authResult;
 99→  }
100→
101→  // Step 2: Derive BrainAction from HTTP method + URL path
102→  const url = new URL(request.url);
103→  const requestedAction = deriveRequestedAction(request.method, url.pathname);
104→
105→  if (!requestedAction) {
106→    return jsonResponse(
107→      { error: "unmapped_route", error_description: "No action mapping for this route" },
108→      403,
109→    );
110→  }
111→
112→  // Step 3: Extract constraints from request body if token has constrained authorizations
113→  const requestedConstraints = await extractRequestConstraints(
114→    request,
115→    requestedAction,
116→    authResult.authorizationDetails,
117→  );
118→
119→  if (requestedConstraints) {
120→    requestedAction.constraints = requestedConstraints;
121→  }
122→
123→  // Step 4: Verify operation scope against token's authorization_details
124→  const verification = verifyOperationScope(requestedAction, authResult.authorizationDetails);
125→
126→  if (!verification.authorized) {
127→    return jsonResponse(
128→      { error: verification.code, error_description: verification.error },
129→      403,
130→    );
131→  }
132→
133→  return authResult;
134→}
135→

