  1→import { betterAuth, APIError } from "better-auth";
  2→import { jwt } from "better-auth/plugins";
  3→import { oauthProvider } from "@better-auth/oauth-provider";
  4→import { RecordId, type Surreal } from "surrealdb";
  5→import { surrealdbAdapter } from "./adapter";
  6→import { BRAIN_SCOPES } from "./scopes";
  7→
  8→export type AuthConfig = {
  9→  betterAuthSecret: string;
 10→  betterAuthUrl: string;
 11→  githubClientId: string;
 12→  githubClientSecret: string;
 13→  selfHosted: boolean;
 14→};
 15→
 16→type EmailAndPasswordConfig = {
 17→  enabled: boolean;
 18→  password?: {
 19→    hash: (password: string) => Promise<string>;
 20→    verify: (params: { hash: string; password: string }) => Promise<boolean>;
 21→  };
 22→};
 23→
 24→type SignupGuardHooks = {
 25→  user: {
 26→    create: {
 27→      before: (user: Record<string, unknown>, context: unknown) => never;
 28→    };
 29→  };
 30→};
 31→
 32→export function buildSignupGuard(selfHosted: boolean): SignupGuardHooks | undefined {
 33→  if (!selfHosted) return undefined;
 34→
 35→  return {
 36→    user: {
 37→      create: {
 38→        before: () => {
 39→          throw new APIError("FORBIDDEN", {
 40→            message: "Registration is disabled",
 41→          });
 42→        },
 43→      },
 44→    },
 45→  };
 46→}
 47→
 48→export function buildEmailAndPasswordConfig(): EmailAndPasswordConfig {
 49→  return {
 50→    enabled: true,
 51→    password: {
 52→      hash: (password: string) => Bun.password.hash(password, "argon2id"),
 53→      verify: ({ hash, password }: { hash: string; password: string }) =>
 54→        Bun.password.verify(password, hash),
 55→    },
 56→  };
 57→}
 58→
 59→export function createAuth(surreal: Surreal, config: AuthConfig) {
 60→  const allScopes = [
 61→    "openid",
 62→    "profile",
 63→    "email",
 64→    "offline_access",
 65→    ...Object.keys(BRAIN_SCOPES),
 66→  ];
 67→
 68→  const signupGuard = buildSignupGuard(config.selfHosted);
 69→
 70→  return betterAuth({
 71→    secret: config.betterAuthSecret,
 72→    baseURL: config.betterAuthUrl,
 73→    basePath: "/api/auth",
 74→    database: surrealdbAdapter(surreal),
 75→    ...(signupGuard ? { databaseHooks: signupGuard } : {}),
 76→    user: {
 77→      modelName: "person",
 78→      fields: {
 79→        email: "contact_email",
 80→        emailVerified: "email_verified",
 81→        createdAt: "created_at",
 82→        updatedAt: "updated_at",
 83→      },
 84→    },
 85→    session: {
 86→      storeSessionInDatabase: true,
 87→      fields: {
 88→        userId: "person_id",
 89→        expiresAt: "expires_at",
 90→        ipAddress: "ip_address",
 91→        userAgent: "user_agent",
 92→        createdAt: "created_at",
 93→        updatedAt: "updated_at",
 94→      },
 95→    },
 96→    account: {
 97→      fields: {
 98→        userId: "person_id",
 99→        accountId: "account_id",
100→        providerId: "provider_id",
101→        accessToken: "access_token",
102→        refreshToken: "refresh_token",
103→        accessTokenExpiresAt: "access_token_expires_at",
104→        refreshTokenExpiresAt: "refresh_token_expires_at",
105→        idToken: "id_token",
106→        createdAt: "created_at",
107→        updatedAt: "updated_at",
108→      },
109→    },
110→    verification: {
111→      fields: {
112→        expiresAt: "expires_at",
113→        createdAt: "created_at",
114→        updatedAt: "updated_at",
115→      },
116→    },
117→    emailAndPassword: buildEmailAndPasswordConfig(),
118→    socialProviders: {
119→      github: {
120→        clientId: config.githubClientId,
121→        clientSecret: config.githubClientSecret,
122→      },
123→    },
124→    plugins: [
125→      jwt(),
126→      oauthProvider({
127→        loginPage: "/sign-in",
128→        consentPage: "/consent",
129→        scopes: allScopes,
130→        validAudiences: [config.betterAuthUrl],
131→        allowDynamicClientRegistration: true,
132→        allowUnauthenticatedClientRegistration: true,
133→        accessTokenExpiresIn: 3600,
134→        refreshTokenExpiresIn: 2592000,
135→        customAccessTokenClaims: async ({ user }) => {
136→          if (!user) return {};
137→          const [memberRows] = await surreal.query<
138→            [Array<{ workspace_id: RecordId<"workspace", string>; workspace_name: string }>]
139→          >(
140→            `SELECT out.id AS workspace_id, out.name AS workspace_name
141→             FROM member_of
142→             WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person)
143→             LIMIT 1;`,
144→            { person: new RecordId("person", user.id) },
145→          );
146→
147→          if (memberRows.length === 0) {
148→            return {};
149→          }
150→
151→          return {
152→            "urn:brain:workspace": memberRows[0].workspace_id.id as string,
153→            "urn:brain:workspace_name": memberRows[0].workspace_name,
154→            "urn:brain:agent_type": "code_agent",
155→          };
156→        },
157→      }),
158→    ],
159→  });
160→}
161→
162→export type Auth = ReturnType<typeof createAuth>;
163→

